#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Update sensor freshness */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (controller->has_valid_temperature) {
            /* Temperature already valid - check for staleness */
            uint32_t age_ms = input.now_ms - controller->last_temperature_ms;
            if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                controller->has_valid_temperature = false;
            }
        } else {
            controller->has_valid_temperature = true;
        }
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        if (controller->has_valid_level) {
            /* Level already valid - check for staleness */
            uint32_t age_ms = input.now_ms - controller->last_level_ms;
            if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                controller->has_valid_level = false;
            }
        } else {
            controller->has_valid_level = true;
        }
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for staleness */
        if (controller->has_valid_temperature) {
            uint32_t age_ms = input.now_ms - controller->last_temperature_ms;
            if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                controller->has_valid_temperature = false;
            }
        }
        if (controller->has_valid_level) {
            uint32_t age_ms = input.now_ms - controller->last_level_ms;
            if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                controller->has_valid_level = false;
            }
        }
        break;
    }

    /* Determine actuator state based on current sensor values */
    bool inlet_open = false;
    bool heater_on = false;
    controller_state_t current_state = CONTROLLER_STATE_SAFE_IDLE;

    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        /* Stay in safe idle when either sensor is stale or invalid */
        goto apply_safe_idle;
    }

    int level = controller->last_level;
    int temp = controller->last_temperature_c;

    /* Control policy: if LEVEL < 60, keep inlet open and heater off */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* Low fill state: inlet open, heater off */
        inlet_open = true;
        heater_on = false;
        current_state = CONTROLLER_STATE_FILLING;
        goto apply_safe_idle;
    }

    /* If LEVEL >= 60 and TEMP < 45, heat the vessel */
    if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
        /* Heating state: level safe, heater on */
        inlet_open = false;
        heater_on = true;
        current_state = CONTROLLER_STATE_HEATING;
        goto apply_safe_idle;
    }

    /* If LEVEL >= 55 (safe level), keep heater off when temp is low */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        /* Below safe heating level: keep heater off regardless of temperature */
        inlet_open = false;
        heater_on = false;
        current_state = CONTROLLER_STATE_HOLDING;
        goto apply_safe_idle;
    }

    /* At or above safe level (>= 55), check temperature bands */
    if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* Above upper band: close inlet, turn off heater */
        inlet_open = false;
        heater_on = false;
        current_state = CONTROLLER_STATE_HOLDING;
        goto apply_safe_idle;
    }

    if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* Near upper band: check if temperature is rising */
        bool temp_rising = controller->last_temperature_c > controller->previous_temperature_c;

        if (temp_rising) {
            /* Temperature rising in the target band: turn off heater early */
            inlet_open = false;
            heater_on = false;
            current_state = CONTROLLER_STATE_HOLDING;
            goto apply_safe_idle;
        } else {
            /* Temperature not rising: hold previous safe state */
            /* If we were heating, keep it on. Otherwise, stay off. */
            inlet_open = false;
            heater_on = controller->heater_on;
            current_state = CONTROLLER_STATE_HOLDING;
            goto apply_safe_idle;
        }
    }

    if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        /* In the middle band: close inlet and turn on heater */
        inlet_open = false;
        heater_on = true;
        current_state = CONTROLLER_STATE_HEATING;
        goto apply_safe_idle;
    }

apply_safe_idle:
    outlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = current_state;
    output.state_name = controller_state_name(current_state);
    output.changed =
        (previous_inlet_open != inlet_open) ||
        (previous_heater_on != heater_on) ||
        (previous_state != current_state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

