    output.inlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = current_state;
    output.state_name = controller_state_name(current_state);
    output.changed =
        (previous_inlet_open != inlet_open) ||
        (previous_heater_on != heater_on) ||
        (previous_state != current_state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

/* C-style wrapper class for testing */
typedef struct {
    controller_t controller;
} ControllerInstance;

ControllerInstance* controller_create(void)
{
    ControllerInstance *inst = malloc(sizeof(ControllerInstance));
    if (inst == NULL) {
        return NULL;
    }
    controller_init(&inst->controller);
    return inst;
}

void controller_destroy(ControllerInstance *inst)
{
    if (inst != NULL) {
        free(inst);
    }
}

